record.field:
{
    "type": "object",
    "properties": {
        "date": {
            "type": "string",
            "description": "Date to get schedule for. Use 'today' (default), 'tomorrow', 'yesterday', or ISO date YYYY-MM-DD"
        }
    }
}

{
    "type": "object",
    "properties": {
        "member_name": {"type": "string", "description": "Name of the member"},
        "member_id": {"type": "integer", "description": "ID of the member"},
        "limit": {"type": "integer", "description": "Max records to return", "default": 10}
    }
}

{
    "type": "object",
    "properties": {
        "member_name": {"type": "string", "description": "Name of the member to check in"},
        "member_id": {"type": "integer", "description": "ID of the member"},
        "session_id": {"type": "integer", "description": "Optional session ID"}
    },
    "required": ["member_name"]
}

{
    "type": "object",
    "properties": {
        "member_name": {"type": "string", "description": "Name of the member to check out"},
        "member_id": {"type": "integer", "description": "ID of the member"}
    },
    "required": ["member_name"]
}

{
    "type": "object",
    "properties": {
        "member_name": {"type": "string", "description": "Name of the member"},
        "session_id": {"type": "integer", "description": "ID of the class session"},
        "checkin_datetime": {"type": "string", "format": "date-time", "description": "Check-in time (defaults to now)"},
        "note": {"type": "string", "description": "Optional note"}
    },
    "required": ["member_name", "session_id"]
}

{
    "type": "object",
    "properties": {
        "session_id": {"type": "integer", "description": "ID of the session to check"},
        "session_name": {"type": "string", "description": "Name of the session"}
    }
}
